css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; background: linear-gradient(135deg, #052e16, #0a3d20); font-family: -apple-system, BlinkMacSystemFont, sans-serif; display: flex; align-items: center; justify-content: center; padding: 20px; }
.app { width: 100%; max-width: 520px; background: rgba(255,255,255,0.07); backdrop-filter: blur(20px); border: 1px solid rgba(255,255,255,0.12); border-radius: 28px; padding: 32px; color: white; }
.app-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; }
h1 { font-size: 32px; font-weight: 900; }
.header-stats { font-size: 14px; color: rgba(255,255,255,0.5); }
.progress-wrap { margin-bottom: 24px; }
.progress-bar { height: 6px; background: rgba(255,255,255,0.1); border-radius: 3px; }
.progress-fill { height: 100%; border-radius: 3px; background: linear-gradient(90deg, #22c55e, #86efac); transition: width 0.4s ease; width: 0%; }
.add-task { display: flex; gap: 10px; margin-bottom: 16px; }
#task-input { flex: 1; height: 48px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.15); background: rgba(255,255,255,0.08); color: white; padding: 0 16px; font-size: 15px; outline: none; } #task-input::placeholder { color: rgba(255,255,255,0.35); }
#priority { height: 48px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.15); background: rgba(255,255,255,0.08); color: white; padding: 0 12px; font-size: 14px; outline: none; cursor: pointer; }
.add-task button { height: 48px; padding: 0 20px; border-radius: 12px; border: none; background: #22c55e; color: white; font-weight: 800; font-size: 15px; cursor: pointer; white-space: nowrap; }
.filters { display: flex; gap: 8px; margin-bottom: 20px; }
.filter { padding: 8px 18px; border-radius: 20px; border: 1px solid rgba(255,255,255,0.15); background: transparent; color: rgba(255,255,255,0.6); font-size: 13px; font-weight: 600; cursor: pointer; transition: all 0.2s; } .filter.active { background: #22c55e; border-color: #22c55e; color: white; }
.task-list { display: flex; flex-direction: column; gap: 10px; }
.task-item { display: flex; align-items: center; gap: 12px; padding: 16px; background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.08); border-radius: 14px; transition: all 0.2s; animation: slideIn 0.3s ease; }
@keyframes slideIn { from { opacity: 0; transform: translateY(-10px); } to { opacity: 1; transform: translateY(0); } }
.task-item.done { opacity: 0.5; } .task-item.done .task-text { text-decoration: line-through; }
.task-check { width: 24px; height: 24px; border-radius: 50%; border: 2px solid rgba(255,255,255,0.3); background: transparent; cursor: pointer; display: flex; align-items: center; justify-content: center; flex-shrink: 0; transition: all 0.2s; } .task-check.checked { background: #22c55e; border-color: #22c55e; }
.task-text { flex: 1; font-size: 15px; font-weight: 500; }
.priority-badge { padding: 3px 10px; border-radius: 20px; font-size: 11px; font-weight: 700; } .high { background: rgba(239,68,68,0.2); color: #f87171; } .normal { background: rgba(255,255,255,0.1); color: rgba(255,255,255,0.5); } .low { background: rgba(34,197,94,0.2); color: #86efac; }
.task-delete { background: none; border: none; color: rgba(255,255,255,0.3); cursor: pointer; font-size: 18px; padding: 4px; transition: color 0.2s; } .task-delete:hover { color: #ef4444; }
.empty-state { text-align: center; color: rgba(255,255,255,0.35); font-size: 15px; padding: 32px; display: none; }

js:
let tasks = [], currentFilter = 'all';
function addTask() {
  const input = document.getElementById('task-input');
  const priority = document.getElementById('priority').value;
  const text = input.value.trim();
  if (!text) return;
  tasks.push({ id: Date.now(), text, done: false, priority });
  input.value = '';
  render();
}
function toggleTask(id) {
  const t = tasks.find(t => t.id === id);
  if (t) { t.done = !t.done; render(); }
}
function deleteTask(id) {
  tasks = tasks.filter(t => t.id !== id);
  render();
}
function filter(f, btn) {
  currentFilter = f;
  document.querySelectorAll('.filter').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  render();
}
function render() {
  const filtered = tasks.filter(t => {
    if (currentFilter === 'active') return !t.done;
    if (currentFilter === 'done') return t.done;
    return true;
  });
  const list = document.getElementById('task-list');
  const empty = document.getElementById('empty');
  const done = tasks.filter(t => t.done).length;
  document.getElementById('done-count').textContent = done;
  document.getElementById('total-count').textContent = tasks.length;
  const pct = tasks.length ? (done / tasks.length * 100) : 0;
  document.getElementById('progress').style.width = pct + '%';
  if (filtered.length === 0) { list.innerHTML = ''; empty.style.display = 'block'; return; }
  empty.style.display = 'none';
  list.innerHTML = filtered.map(t => `
    <div class="task-item ${t.done ? 'done' : ''}">
      <div class="task-check ${t.done ? 'checked' : ''}" onclick="toggleTask(${t.id})">${t.done ? '✓' : ''}</div>
      <span class="task-text">${t.text}</span>
      <span class="priority-badge ${t.priority}">${t.priority === 'high' ? 'Yüksek' : t.priority === 'low' ? 'Düşük' : 'Normal'}</span>
      <button class="task-delete" onclick="deleteTask(${t.id})">×</button>
    </div>
  `).join('');
}
render();
